'use client';

/**
 * Button to initiate a VOIP call
 * Note: Full VOIP functionality requires Twilio SDK integration
 */

import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Phone, PhoneOff, Loader2 } from 'lucide-react';
import { toast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';

interface CallButtonProps {
    phoneNumber: string;
    contactName?: string;
    variant?: 'default' | 'ghost' | 'outline';
    size?: 'default' | 'sm' | 'lg' | 'icon';
    disabled?: boolean;
    className?: string;
}

export function CallButton({
    phoneNumber,
    contactName,
    variant = 'default',
    size = 'icon',
    disabled,
    className
}: CallButtonProps) {
    const [isDialing, setIsDialing] = useState(false);

    const handleCall = async () => {
        if (!phoneNumber || isDialing) return;

        setIsDialing(true);

        try {
            // TODO: Integrate with Twilio SDK for actual VOIP calls
            // For now, show a placeholder toast

            toast({
                title: 'Iniciando chamada...',
                description: `Ligando para ${contactName || phoneNumber}`,
            });

            // Simulate call initiation delay
            await new Promise(resolve => setTimeout(resolve, 1000));

            // In a real implementation, this would:
            // 1. Get a Twilio token from the server
            // 2. Initialize the Twilio Device
            // 3. Make the call

            toast({
                title: 'VOIP não configurado',
                description: 'Configure as credenciais do Twilio para fazer chamadas.',
                variant: 'destructive'
            });
        } catch (error) {
            console.error('Call error:', error);
            toast({
                title: 'Erro ao ligar',
                description: 'Não foi possível iniciar a chamada.',
                variant: 'destructive'
            });
        } finally {
            setIsDialing(false);
        }
    };

    return (
        <Button
            variant={variant}
            size={size}
            onClick={handleCall}
            disabled={disabled || isDialing || !phoneNumber}
            className={cn(
                'transition-colors',
                isDialing && 'animate-pulse',
                className
            )}
        >
            {isDialing ? (
                <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
                <Phone className="h-4 w-4" />
            )}
        </Button>
    );
}

export function EndCallButton({
    onEnd,
    className
}: {
    onEnd: () => void;
    className?: string;
}) {
    return (
        <Button
            variant="destructive"
            size="icon"
            onClick={onEnd}
            className={cn('rounded-full', className)}
        >
            <PhoneOff className="h-4 w-4" />
        </Button>
    );
}
